import{_ as o,o as e,c as n,ag as r}from"./chunks/framework.DUvHsH_U.js";const p=JSON.parse('{"title":"Points, Coupons, and Loyalty Program Setup","description":"","frontmatter":{},"headers":[],"relativePath":"offers-loyalty/points-coupons-and-loyalty-program-setup.md","filePath":"offers-loyalty/points-coupons-and-loyalty-program-setup.md","lastUpdated":1777975835000}'),i={name:"offers-loyalty/points-coupons-and-loyalty-program-setup.md"};function s(l,t,a,g,u,c){return e(),n("div",null,[...t[0]||(t[0]=[r('<h1 id="points-coupons-and-loyalty-program-setup" tabindex="-1">Points, Coupons, and Loyalty Program Setup <a class="header-anchor" href="#points-coupons-and-loyalty-program-setup" aria-label="Permalink to &quot;Points, Coupons, and Loyalty Program Setup&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>This setup allows customers to see their loyalty points in the mobile app, convert available points into discount coupons, and apply those coupons during checkout. When configured correctly, the customer can redeem a voucher, see it in their available coupons, and receive the correct discount on the order total.</p><h2 id="erpnext-setup-steps" tabindex="-1">ERPNext Setup Steps <a class="header-anchor" href="#erpnext-setup-steps" aria-label="Permalink to &quot;ERPNext Setup Steps&quot;">​</a></h2><ol><li><p><strong>Log in as an Administrator</strong></p><ul><li>Open the ERPNext admin dashboard.</li><li>Log in with a System Manager or Administrator account.</li></ul></li><li><p><strong>Grant Customer access to loyalty and coupon records</strong></p><ul><li>Use the ERPNext search bar.</li><li>Search for <strong>Role Permissions Manager</strong> and open it.</li><li>In the <strong>Document Type</strong> field, select <strong>Loyalty Point Log</strong>.</li><li>Add or confirm a row for the <strong>Customer</strong> role.</li><li>Check <strong>Read</strong> and <strong>Write</strong>.</li><li>Click <strong>Save</strong>.</li><li>Change the <strong>Document Type</strong> field to <strong>Coupon Code</strong>.</li><li>Add or confirm a row for the <strong>Customer</strong> role.</li><li>Check <strong>Read</strong> and <strong>Write</strong>.</li><li>Click <strong>Save</strong>.</li><li>Change the <strong>Document Type</strong> field to <strong>Pricing Rule</strong>.</li><li>Add or confirm a row for the <strong>Customer</strong> role.</li><li>Check <strong>Read</strong> only.</li><li>Click <strong>Save</strong>.</li></ul></li><li><p><strong>Open Mobile E-Commerce Settings</strong></p><ul><li>Use the ERPNext search bar.</li><li>Search for <strong>Mobile E-Commerce Settings</strong> and open it.</li><li>Open the <strong>Loyalty Program Settings</strong> tab.</li></ul></li><li><p><strong>Fill the general loyalty settings</strong></p><ul><li>In <strong>Earning Percent (%)</strong>, enter the percentage of the order value that should become points.</li><li>In <strong>Point Value</strong>, enter the money value of each point, according to the client&#39;s loyalty rules.</li><li>In <strong>Voucher Validity Days</strong>, enter how many days a generated voucher should remain usable.</li><li>In <strong>Signup Bonus Points</strong>, enter the number of points new customers should receive after signup.</li><li>In <strong>Signup Pricing Rule</strong>, select the Pricing Rule used for the signup voucher.</li><li>In <strong>Signup Voucher Value</strong>, enter the discount value for the signup voucher.</li><li>Click <strong>Save</strong> after filling these fields.</li></ul></li><li><p><strong>Configure the Tiers table</strong></p><ul><li>Stay in <strong>Mobile E-Commerce Settings</strong>.</li><li>In the <strong>Loyalty Program Settings</strong> tab, find the <strong>Tiers</strong> table.</li><li>Add one row for each point-to-voucher option that should appear in the mobile app.</li><li>In each row, select the correct <strong>Pricing Rule</strong>.</li><li>In <strong>Voucher Value</strong>, enter the discount amount the customer will receive.</li><li>In <strong>Points Required</strong>, enter how many points the customer must spend to generate that voucher.</li><li>Example: enter <strong>1000</strong> in <strong>Points Required</strong> and <strong>100</strong> in <strong>Voucher Value</strong> if 1000 points should generate a 100-value voucher.</li><li>Click <strong>Save</strong>.</li></ul></li><li><p><strong>Create or open the Pricing Rule for each voucher tier</strong></p><ul><li>Use the ERPNext search bar.</li><li>Search for <strong>Pricing Rule List</strong> and open it.</li><li>Open the Pricing Rule selected in the <strong>Tiers</strong> table, or click <strong>New</strong> to create one.</li><li>Enter a clear title, such as <strong>Loyalty Voucher 100</strong>.</li></ul></li><li><p><strong>Set the required Pricing Rule checkboxes</strong></p><ul><li>On the Pricing Rule document, check <strong>Coupon Code Based</strong>.</li><li>In the <strong>Party Information</strong> section, check <strong>Selling</strong>.</li><li>Confirm <strong>Disabled</strong> is unchecked.</li></ul></li><li><p><strong>Set the required Pricing Rule discount options</strong></p><ul><li>In <strong>Apply On</strong>, select <strong>Transaction</strong>.</li><li>In <strong>Price or Product Discount</strong>, select <strong>Price</strong>.</li><li>In <strong>Valid From</strong>, select a date on or before the testing date.</li><li>In <strong>Valid Upto</strong>, select a date on or after the testing date.</li><li>In <strong>Discount Amount</strong>, enter the exact discount amount for this voucher.</li><li>Click <strong>Save</strong>.</li></ul></li><li><p><strong>Repeat the Pricing Rule setup for all tiers</strong></p><ul><li>Return to <strong>Mobile E-Commerce Settings</strong>.</li><li>Review every row in the <strong>Tiers</strong> table.</li><li>Confirm each row points to a Pricing Rule that has the required settings above.</li><li>Save the settings again after any change.</li></ul></li><li><p><strong>Verify generated coupons during testing</strong></p><ul><li>Go to <strong>Coupon Code List</strong>.</li><li>After a customer converts points in the mobile app, search for that customer.</li><li>Confirm a new coupon exists for the customer.</li><li>Confirm the coupon has a valid <strong>Valid From</strong> and <strong>Valid Upto</strong> date.</li><li>Confirm the coupon is linked to the correct <strong>Pricing Rule</strong>.</li><li>Confirm the coupon is not marked as used before checkout.</li></ul></li><li><p><strong>Test the full mobile flow</strong></p><ul><li>Log in to the mobile app as the test customer.</li><li>Open the points or rewards screen.</li><li>Confirm the customer can see their points balance and available voucher tiers.</li><li>Convert enough points into a coupon.</li><li>Confirm the app shows a success message.</li><li>Open the coupons list and confirm the new coupon is visible.</li><li>Add products to the cart and continue to checkout.</li><li>Select the coupon.</li><li>Place the order.</li><li>Confirm the order total is reduced by the configured discount amount.</li></ul></li></ol><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><ul><li><p><strong>If the app shows no available rewards</strong></p><ul><li>Check <strong>Mobile E-Commerce Settings</strong>.</li><li>Open the <strong>Loyalty Program Settings</strong> tab.</li><li>Confirm the <strong>Tiers</strong> table is not empty.</li><li>Confirm each tier has a <strong>Pricing Rule</strong>, <strong>Voucher Value</strong>, and <strong>Points Required</strong>.</li><li>If the table is empty, the app has no voucher options to show.</li></ul></li><li><p><strong>If the customer cannot convert points to a coupon</strong></p><ul><li>Check whether the customer has enough points for the selected tier.</li><li>Check whether the <strong>Tiers</strong> table is empty or misconfigured.</li><li>Confirm the selected tier has a valid <strong>Pricing Rule</strong>.</li><li>Confirm the <strong>Customer</strong> role has <strong>Write</strong> permission for <strong>Loyalty Point Log</strong> and <strong>Coupon Code</strong>.</li><li>In the app, the customer may see an insufficient points message or a failed redemption message.</li></ul></li><li><p><strong>If the coupon is generated but does not appear in the coupon list</strong></p><ul><li>Go to <strong>Coupon Code List</strong>.</li><li>Open the generated coupon.</li><li>Confirm the coupon belongs to the same customer who is logged in to the mobile app.</li><li>Confirm <strong>Valid From</strong> is today or earlier.</li><li>Confirm <strong>Valid Upto</strong> is today or later.</li><li>Confirm the coupon is not marked as used.</li><li>In the app, the customer will see an empty coupon list or the coupon count will not increase.</li></ul></li><li><p><strong>If the coupon is generated but says invalid or does not apply a discount at checkout</strong></p><ul><li>Immediately open the underlying <strong>Pricing Rule</strong>.</li><li>Confirm <strong>Disabled</strong> is unchecked.</li><li>Confirm <strong>Valid From</strong> and <strong>Valid Upto</strong> cover today.</li><li>Confirm <strong>Apply On</strong> is set to <strong>Transaction</strong>.</li><li>Confirm <strong>Coupon Code Based</strong> is checked.</li><li>Confirm <strong>Price or Product Discount</strong> is set to <strong>Price</strong>.</li><li>Confirm <strong>Discount Amount</strong> is filled with the correct value.</li><li>In the app, the customer may be able to select the coupon but the order total will not decrease correctly.</li></ul></li><li><p><strong>If the discount amount is wrong</strong></p><ul><li>Open the <strong>Pricing Rule</strong> used by the coupon.</li><li>Check <strong>Discount Amount</strong>.</li><li>Return to <strong>Mobile E-Commerce Settings</strong> and compare it with the tier&#39;s <strong>Voucher Value</strong>.</li><li>Make both values match the client&#39;s intended voucher value.</li></ul></li><li><p><strong>If the coupon works once but appears again after checkout</strong></p><ul><li>Go to <strong>Coupon Code List</strong>.</li><li>Open the coupon used in the order.</li><li>Confirm it is marked as used after checkout.</li><li>Confirm the <strong>Customer</strong> role has <strong>Write</strong> permission for <strong>Coupon Code</strong>.</li><li>If this is not configured, the customer may physically see the same coupon again even though it should no longer be available.</li></ul></li></ul>',7)])])}const d=o(i,[["render",s]]);export{p as __pageData,d as default};
